146	        let mut waker_registered = false;
147	        loop {
148	            assert!(!self.done);
149	            let closed = self.owner.is_closed();
150	            if let Some(item) = self.owner.try_pop() {
151	                self.done = true;
152	                break Poll::Ready(Some(item));
153	            }
154	            if closed {
