169	pub struct PopSliceFuture<'a, 'b, A: AsyncConsumer + ?Sized>
170	where
171	    A::Item: Copy,
172	{
173	    owner: &'a mut A,
174	    slice: Option<&'b mut [A::Item]>,
175	    count: usize,
176	}
